B.a49=new A.bT(B.Ai,[4294970632,4294970633,4294967553,4294968577,4294968578,4294969089,4294969090,4294967555,4294971393,4294968065,4294968066,4294968067,4294968068,4294968579,4294970625,4294970626,4294970627,4294970882,4294970628,4294970629,4294970630,4294970631,4294970884,4294970885,4294969871,4294969873,4294969872,4294967304,4294968833,4294968834,4294970369,4294970370,4294970371,4294970372,4294970373,4294970374,4294970375,4294971394,4294968835,4294971395,4294968580,4294967556,4294970634,4294970635,4294968321,4294969857,4294970642,4294969091,4294970636,4294970637,4294970638,4294970639,4294970640,4294970641,4294969092,4294968581,4294969093,4294968322,4294968323,4294968324,4294970703,4294967423,4294970643,4294970644,4294969108,4294968836,4294968069,4294971396,4294967309,4294968325,4294967323,4294967323,4294968326,4294968582,4294970645,4294969345,4294969354,4294969355,4294969356,4294969357,4294969358,4294969359,4294969360,4294969361,4294969362,4294969363,4294969346,4294969364,4294969365,4294969366,4294969367,4294969368,4294969347,4294969348,4294969349,4294969350,4294969351,4294969352,4294969353,4294970646,4294970647,4294970648,4294970649,4294970650,4294970651,4294970652,4294970653,4294970654,4294970655,4294970656,4294970657,4294969094,4294968583,4294967558,4294967559,4294971397,4294971398,4294969095,4294969096,4294969097,4294969098,4294970658,4294970659,4294970660,4294969105,4294969106,4294969109,4294971399,4294968584,4294968841,4294969110,4294969111,4294968070,4294967560,4294970661,4294968327,4294970662,4294969107,4294969112,4294969113,4294969114,4294971905,4294971906,4294971400,4294970118,4294970113,4294970126,4294970114,4294970124,4294970127,4294970115,4294970116,4294970117,4294970125,4294970119,4294970120,4294970121,4294970122,4294970123,4294970663,4294970664,4294970665,4294970666,4294968837,4294969858,4294969859,4294969860,4294971402,4294970667,4294970704,4294970715,4294970668,4294970669,4294970670,4294970671,4294969861,4294970672,4294970673,4294970674,4294970705,4294970706,4294970707,4294970708,4294969863,4294970709,4294969864,4294969865,4294970886,4294970887,4294970889,4294970888,4294969099,4294970710,4294970711,4294970712,4294970713,4294969866,4294969100,4294970675,4294970676,4294969101,4294971401,4294967562,4294970677,4294969867,4294968071,4294968072,4294970714,4294968328,4294968585,4294970678,4294970679,4294970680,4294970681,4294968586,4294970682,4294970683,4294970684,4294968838,4294968839,4294969102,4294969868,4294968840,4294969103,4294968587,4294970685,4294970686,4294970687,4294968329,4294970688,4294969115,4294970693,4294970694,4294969869,4294970689,4294970690,4294967564,4294968588,4294970691,4294967569,4294969104,4294969601,4294969602,4294969603,4294969604,4294969605,4294969606,4294969607,4294969608,4294971137,4294971138,4294969870,4294970692,4294968842,4294970695,4294967566,4294967567,4294967568,4294970697,4294971649,4294971650,4294971651,4294971652,4294971653,4294971654,4294971655,4294970698,4294971656,4294971657,4294971658,4294971659,4294971660,4294971661,4294971662,4294971663,4294971664,4294971665,4294971666,4294971667,4294970699,4294971668,4294971669,4294971670,4294971671,4294971672,4294971673,4294971674,4294971675,4294967305,4294970696,4294968330,4294967297,4294970700,4294971403,4294968843,4294970701,4294969116,4294969117,4294968589,4294968590,4294970702],t.eL)
B.a7u={"Extensor Hallucis":0,"Medial Gastroc":1,"Peroneus Longus":2,"Tibialis Ant":3,"Tibialis Post":4,"Vastus Lateralis":5}
B.a73=new A.hB("Extensor Hallucis Longus","Deep Peroneal Nerve, Common Peroneal Nerve, Sciatic Nerve, Posterior Division Sacral Plexus, L5, S1","From the midportion of the fibular shaft and the adjacent interosseous membrane.","The dorsal base of the distal phalanx of the great toe.","Have the patient lie supine with the leg fully extended and relaxed.","Measure three fingerbreadths above the bimalleolar line at the ankle. Move just lateral to the sharp crest of the tibia, and immediately lateral to the thick, easily palpable Tibialis Anterior tendon. Insert the needle here.","Ask the patient to forcefully extend their big toe upward toward their face.","If the electrode is inserted too superficially or too far proximally up the leg, you will end up in the massive Tibialis Anterior. If inserted too far laterally, you may hit the Peroneus Tertius.","This muscle is an excellent diagnostic target because it allows you to clearly differentiate an L5 radiculopathy from an isolated peroneal neuropathy. While the Tibialis Anterior is primarily L4-L5, the Extensor Hallucis Longus has a stronger L5-S1 representation. In cases of acute anterior compartment syndrome, this muscle will rapidly show signs of severe ischemic necrosis and profound electrical silence.","assets/images/emg/Extensor Hallucis longus.png")
B.a6Z=new A.hB("Gastrocnemius: Medial Head","Tibial Nerve, Sciatic Nerve, Ventral Division Sacral Plexus, S1, S2","The medial condyle and popliteal surface of the femur.","It merges with the soleus to form the massive Achilles tendon, anchoring into the posterior calcaneus.","Have the patient lie prone with their feet hanging relaxed over the edge of the examination bed.","Measure one handbreadth below the popliteal crease at the back of the knee. Insert the needle directly into the apex of the prominent medial muscle mass of the calf.","Instruct the patient to forcefully plantar flex their foot (point their toes like a ballerina) while keeping their knee perfectly straight.","If the needle is driven too deeply through the thick gastrocnemius belly, it will enter the underlying, flatter soleus muscle.","The medial head is anatomically larger and extends slightly further down the leg than the lateral head, making it the preferred target for routine EMG evaluation of the tibial nerve. It is an absolute powerhouse muscle for walking and running. Weakness or denervation here is a classic hallmark of a severe S1 radiculopathy originating in the lumbosacral spine.","assets/images/emg/Medial Gastroc.png")
B.a71=new A.hB("Peroneus Longus","Superficial Peroneal Nerve, Common Peroneal Nerve, Sciatic Nerve, Posterior Division Sacral Plexus, L5, S1, S2","The head of the fibula and the upper two-thirds of the lateral fibular shaft.","It wraps under the foot to insert into the base of the first metatarsal and the medial cuneiform bone.","Have the patient lie supine with their leg slightly internally rotated.","Palpate the prominent bony head of the fibula near the knee. Measure exactly three fingerbreadths distally down the lateral leg. Insert the needle directing it toward the lateral aspect of the fibula bone.","Instruct the patient to forcefully plantar flex and evert their foot (pushing the outer edge of their foot away).","If the electrode is angled too far posteriorly, you will mistakenly sample the lateral gastrocnemius or soleus. If angled too far anteriorly, you will cross into the anterior compartment and hit the extensor digitorum longus.","This muscle is your primary target for evaluating the integrity of the superficial peroneal nerve. Because the common peroneal nerve wraps tightly around the fibular neck just above this muscle, the Peroneus Longus is highly susceptible to compressive injuries from tight casts, knee braces, or habitual leg crossing. Its tendon provides crucial dynamic support for the transverse arch of the foot.","assets/images/emg/Fibularis longus.png")
B.a74=new A.hB("Tibialis Anterior","Deep Peroneal Nerve, Common Peroneal Nerve, Sciatic Nerve, Posterior Division Sacral Plexus, L4, L5","The upper two-thirds of the lateral surface of the tibia and the adjacent interosseous membrane.","The medial and plantar surfaces of the medial cuneiform bone, and the base of the first metatarsal.","Have the patient lie supine with their leg fully relaxed.","In the upper one-third of the lower leg, locate the sharp, prominent tibial crest (the shin bone). Move exactly one fingerbreadth laterally off the bone into the thick muscle belly and insert the needle.","Ask the patient to forcefully dorsiflex their foot, bringing their toes up toward their knee.","The primary pitfall here is failing to insert the needle deeply enough into the bulk of the muscle, resulting in a poor or noisy recording due to superficial fascial interference.","The Tibialis Anterior is the undisputed king of foot dorsiflexion. When this muscle fails due to a deep peroneal nerve injury or an L5 radiculopathy, the patient develops a devastating 'foot drop,' forcing them to adopt a high-stepping, slapping gait to avoid tripping over their own toes. It is the most critical muscle to sample when evaluating any anterior compartment pathology.","assets/images/emg/Tibialis Anterior.png")
B.a78=new A.hB("Tibialis Posterior","Tibial Nerve, Sciatic Nerve, Anterior Division Sacral Plexus, L5, S1","The interosseous membrane, the posterior surface of the tibia, and the upper two-thirds of the medial fibula.","The tuberosity of the navicular bone, sending strong aponeurotic slips across the plantar foot to the cuneiforms and metatarsal bases.","Have the patient lie prone with their feet hanging over the edge of the bed and the thigh slightly internally rotated to expose the medial calf.","Measure one full handbreadth distal to the tibial tuberosity. Move exactly one fingerbreadth off the medial edge of the tibia bone. Direct the needle strictly obliquely through the soleus and flexor digitorum longus, staying tightly posterior to the tibia bone.","Instruct the patient to invert their foot while holding it in plantar flexion.","CAUTION: The major neurovascular bundle (Posterior Tibial Artery and Nerve) lies dangerously close. Never direct the needle indiscriminately strictly laterally. Stick tight to the posterior cortex of the tibia. If inserted too superficially, you will only sample the soleus.","This is the deepest, most difficult to reach muscle in the posterior compartment of the leg, but it is a critical diagnostic target. The Tibialis Posterior is the strongest dynamic supporter of the longitudinal arch of the foot. Unlike the superficial calf muscles, it is heavily innervated by the L5 root via the Tibial nerve, making it an excellent discriminator when untangling complex lumbosacral plexopathies.","assets/images/emg/Tibialis Posterior.png")
B.a75=new A.hB("Vastus Lateralis","Femoral Nerve, Posterior Division Lumbar Plexus, L2, L3, L4","The intertrochanteric line, the greater trochanter, the gluteal tuberosity, and the linea aspera of the femur.","It merges into the quadriceps tendon, ultimately anchoring onto the tibial tubercle.","Have the patient lie supine with their leg fully extended.","Locate the massive lateral aspect of the thigh. Measure one full handbreadth directly above the superior pole of the patella and insert the needle into the thick muscle belly.","Ask the patient to lift their heel slightly off the bed while keeping their knee perfectly straight and locked.","If the electrode is inserted too far posteriorly on the thigh, you will inadvertently sample the biceps femoris (hamstrings). If inserted too far medially, you will enter the rectus femoris.","As the largest component of the quadriceps femoris, this muscle is the primary shock absorber and extensor of the knee. When this muscle is paralyzed by a severe femoral neuropathy, the patient loses the ability to keep their knee locked in extension. They will describe a terrifying sensation that their knee is constantly trying to buckle and collapse whenever they place weight on the leg during walking.","assets/images/emg/Vastus Lateralis.png")
