b0=A.cf(A.a(["Dynamic Ultrasound of the Scapula: Confirms abnormal scapular tracking during protraction consistent with serratus anterior dysfunction (winging).","MRI Shoulder/Neck: No evidence of cervical root compression or mass in the supraclavicular fossa."],af3),b0)
