b1=A.ce(aa3,b3,s2,"INDICATED (To differentiate from radiculopathy and muscle strain)",A.a([A.t(!0,f0,f0,q4,f0,f0,t7,t8,f0,h4,m9,f0),A.t(!0,f0,f0,j8,f0,f0,"Adductor Magnus","Obturator/Sciatic",f0,h4,"L2-S1",f0),A.t(!0,f0,f0,j8,f0,f0,"Gracilis",t8,f0,h4,aa5,f0),A.t(!1,"Spared (rules out radiculopathy/plexopathy)",f0,f0,f0,f0,m7,m8,f0,f0,m9,f0),A.t(!1,z0,f0,f0,f0,f0,n0,m8,f0,f0,aa5,f0),A.t(!1,aa6,f0,f0,f0,f0,l5,l6,f0,f0,l7,f0),A.t(!1,aa6,f0,f0,f0,f0,m4,m5,f0,f0,m6,f0),A.t(!1,f0,f0,f0,f0,f0,"Lumbar Paraspinals (L2-L3)",f0,f0,f0,f0,f0)],n),"Isolated obturator neuropathy localizing to the adductor group. Localization is confirmed by **isolated weakness of hip adduction**, **medial thigh sensory loss**, and **sparing of the quadriceps/psoas (femoral)** and lumbar paraspinals. EMG shows denervation in the adductor longus/brevis while femoral-innervated muscles remain normal.",b2,"obturator",b4,ae8,ae7,!0,b1,A.a(["The obturator nerve provides motor innervation to the adductor longus, brevis, magnus, and gracilis.","It provides sensory innervation to a small area on the medial mid-thigh.","Localization Pearl: Isolated adductor weakness with **Normal Quadriceps** and **Normal Patellar Reflex** is the clinical hallmark.","Common causes include pelvic surgery, pregnancy (compression by fetal head), or obturator hernias."],af3),"Groin Pain and Inner Thigh Weakness")
ae7=A.cd(32,"6-month history of progressive weakness and fatigue, worse with exercise",d5,"Symptoms initially affected eyelids causing ptosis, then progressed to difficulty speaking and chewing. Weakness is notably worse at the end of the day or after physical activity. Some improvement with rest.",i4,"Teacher",i4)
ae8=A.ch("Bilateral ptosis, worse on sustained up-gaze","Normal muscle bulk","2+ and symmetric; NO fatigue of reflexes (distinguishes from LEMS)",s1,r5,"Positive ice pack test (improvement in ptosis)","Proximal muscle weakness (4/5) initially, dropping to 3/5 with repetitive testing. Fatigable weakness of extraocular muscles.")
b4=A.a([A.V(aa7,d9),A.V(aa8,"LEMS typically shows *facilitation* (amplitude increase) after exercise and depressed reflexes; here reflexes are normal and there is a decrement on RNS."),A.V("Botulism","Acute onset with autonomic symptoms (dilated pupils, ileus) and rapidly progressive descending paralysis; here symptoms are chronic and fluctuating."),A.V("Thyroid Eye Disease","Would cause proptosis and lid retraction rather than ptosis, and standard RNS would be normal."),A.V("Congenital Myasthenic Syndrome","Usually presents in infancy or early childhood with fixed or fluctuating weakness.")],ae9)
b2=A.a5(["constitutional","Normal weight. Occasional fatigue at the end of the day.","musculoskeletal","Proximal limb weakness, especially after climbing stairs or prolonged standing.","neurological","Bilateral ptosis, double vision (diplopia), difficulty swallowing (dysphagia), and change in voice (nasal speech) after long conversations.","ophthalmological","Intermittent drooping of eyelids, worse when tired."],af1,af1)
b3=A.a(["AChR Binding Antibody: 8.5 nmol/L (Significantly Elevated)","Muscle-Specific Kinase (MuSK) Antibody: Negative","TSH: 1.8 mIU/L (Normal)"],af3)
