b6=A.ce(ab5,b8,s2,"INDICATED (Demyelinating vs Axonal)",A.a([A.t(!0,f0,f0,f0,f0,l3,g9,h0,f0,h4,h1,f0),A.t(!0,ac3,f0,f0,f0,l3,m7,m8,f0,h4,m9,f0),A.t(!0,ac3,f0,f0,f0,l3,r7,z2,f0,h4,"C5",f0),A.t(!0,f0,f0,f0,f0,l3,l5,l6,f0,h4,q3,f0),A.t(!1,"Often spared despite root involvement",f0,f0,f0,f0,"Lumbar Paraspinals (L4)",f0,f0,f0,f0,f0)],n),"Chronic polyradiculoneuropathy (>8 weeks progression) with proximal and distal weakness and generalized areflexia. NCS shows hallmark demyelinating features: prolonged distal latencies, marked velocity slowing (<70% LLN), temporal dispersion, and prolonged F-waves.",b7,"cidp",b9,ae8,ae7,!0,b6,A.a(["CIDP is a chronic demyelinating polyneuropathy characterized by progression >8 weeks.","NCS hallmark: Criteria for demyelination include 1) Prolonged distal latency, 2) Conduction velocity <70% LLN, 3) Abnormal F-waves, and 4) Conduction block or temporal dispersion.","Albuminocytologic dissociation (High protein, normal cell count) in CSF is common.","Proximal weakness is as common as distal weakness in CIDP/GBS because the roots (polyradiculopathy) are involved."],af3),"Chronic Progressive Weakness and Sensory Loss")
ae7=A.cd(55,"1-year history of progressive weakness in the right hand and forearm",i1,"55-year-old male who noticed difficulty with grip strength and occasional dropping of tools. Over the last 6 months, he has developed a significant 'wrist drop' on the right side. No pain, numbness, or tingling. He denies any swallowing or speaking difficulties. His legs are strong and he has no bowel or bladder issues.",ab0,"Gardener",aa9)
ae8=A.ch("Moderate atrophy of the first dorsal interosseous and thenar muscles on the right. No fasciculations observed in the tongue or other limbs.",ac0,"2+ and symmetric throughout. Babinski is negative (flexor). No Hoffmann's sign.",v3,"Entirely normal light touch, pinprick, vibration, and proprioception in all 4 limbs.","Negative Spurling's test. No upper motor neuron (UMN) signs.","Right side: Wrist extension 3/5, Finger extension 3/5, APB 2/5, FDI 3/5. Elbow flexion/extension 5/5. Left side: 5/5 throughout. Lower extremities: 5/5 throughout.")
b9=A.a([A.V(ab3,d9),A.V(ab1,"ALS would typically involve UMN signs (brisk reflexes, Babinski) and is rarely focal to one nerve's distribution for a year without spreading or fasciculations; here reflexes are normal and sensory SNAPs are preserved."),A.V("Lewis-Sumner Syndrome (MADSAM)","MADSAM is a variant of CIDP that involves sensory nerves; here the sensory SNAPs are entirely normal, localizing the lesion to motor fibers only."),A.V("C7 or C8 Radiculopathy","Radiculopathy would be associated with neck pain and usually spares the distal motor responses (no conduction block); also, paraspinals would be abnormal."),A.V("Vasculitic Mononeuritis Multiplex","Vasculitis typically causes painful, axonal loss (amplitude drop) and involves sensory nerves (SNAP loss); here it is painless and demyelinating (block).")],ae9)
b7=A.a5(["constitutional",u6,"musculoskeletal","Right hand weakness. No joint pain.","neurological","Pure motor weakness. No numbness or tingling. No cranial nerve symptoms."],af1,af1)
b8=A.a(["Anti-GM1 Ganglioside Antibody: Positive (High Titer)","Creatine Kinase (CK): 250 U/L (Mildly Elevated)","SPEP: Normal"],af3)
b8=A.cf(A.a(["MRI Brachial Plexus: Normal; no masses or root thickening.","Ultrasound Median Nerve: Focal swelling at the mid-forearm (site of conduction block)."],af3),b8)
c0=A.a([A.ac(!1,"42.0",ac4,e6,p4,i8),A.ac(!1,"38.0",ac4,f1,g1,n7),A.ac(!1,"26.0",ac4,f3,f4,f6)],q)
c1=A.a([A.al(!1,"11.5",f0,g6,w9,p1),A.al(!0,f8,"63% Conduction Block at Forearm",u7,x0,l1),A.al(!1,g2,f0,i6,ac5,p1),A.al(!1,"13.5",f0,aa2,ac6,j5)],o)
