c0=A.ce(ac9,c2,k0,e2,A.a([A.t(!0,f0,f0,h2,f0,l9,"Abductor Hallucis","Medial plantar",f0,h4,m6,f0),A.t(!0,f0,f0,h2,f0,l9,"Abductor Digiti Quinti (Foot)","Lateral plantar",f0,h4,m6,f0),A.t(!1,h7,f0,f0,f0,f0,l5,l6,f0,f0,l7,f0),A.t(!1,h7,f0,f0,f0,f0,m0,l6,f0,f0,m1,f0),A.t(!1,h7,f0,f0,f0,f0,m2,q6,f0,f0,m1,f0),A.t(!1,h7,f0,f0,f0,f0,m7,m8,f0,f0,q8,f0),A.t(!1,f0,f0,f0,f0,f0,m4,m5,f0,f0,m6,f0),A.t(!1,f0,f0,f0,f0,f0,ad2,ad3,f0,f0,r4,f0),A.t(!1,f0,f0,f0,f0,f0,ad4,f0,f0,f0,f0,k6)],n),"Focal entrapment of the posterior tibial nerve at the flexor retinaculum. Diagnosis is confirmed by the specific involvement of the medial and lateral plantar nerves (both sensory and motor) with sparing of proximal tibial muscles (Gastrocnemius), normal Achilles reflexes, and normal Sural SNAPs.",c1,"tarsal",c3,ae8,ae7,!0,c0,A.a(["Tarsal Tunnel Syndrome (TTS) involves compression of the posterior tibial nerve behind the medial malleolus.","Normal Sural and Superficial Fibular SNAPs help rule out more proximal lesions (Sciatic/Plexus) or generalized polyneuropathy.","Specialized plantar nerve studies (Mixed or Sensory) are necessary for diagnosis as standard Tibial motor studies may be normal early on."],af3),"Foot Numbness and Burning Pain")
ae7=A.cd(52,"Lower back pain radiating to posterior leg and lateral foot",i1,"4-month history of lower back pain following heavy lifting at work. Pain radiates down posterior aspect of right leg to lateral foot. Associated numbness in lateral foot and weakness in plantarflexion (toe walking). Pain worse with sitting and forward flexion.","Ibuprofen, gabapentin",r1,i4)
