c6=A.a([A.V("Severe Carpal Tunnel Syndrome",d9),A.V(v8,"A C6 radiculopathy would typically spare the Median SNAP (pre-ganglionic); while the SNAP is absent here due to severe nerve damage, the paraspinals and non-median C6 muscles are normal."),A.V("Median Neuropathy at the Elbow (Pronator)","Pronator syndrome would involve proximal median-innervated muscles (FCR, PT) and cause sensory loss in the palm (palmar cutaneous branch); here those are spared."),A.V("Grip/Motor Branch Entrapment","Would cause weakness but not the profound sensory loss seen here."),A.V(ac1,"Polyneuropathy is typically symmetric and affects the feet first (stocking-glove); here findings are focal to the Median nerve.")],ae9)
